import React from 'react';
import s from './NavFriends.module.css'

const NavFriends = () => {
    return (
        <div className={s.navfriends}>
            <li>friend 1</li>
            <li>friend 2</li>
            <li>friend 3</li>
            <li>friend 4</li>
            <li>friend 5</li>
        </div>

    )
}
 export default NavFriends ;
